def send_single_message(sender,content,custom_props_attributes):
    json_dict = json.loads(content)
    custom_props = { key: json_dict[key]  for key in json_dict if key in custom_props_attributes}
    message = ServiceBusMessage(content,content_type='application/json',application_properties=custom_props)
    sender.send_messages(message)

